mapper.select:
SELECT *
FROM TC_MAIL_FORM
WHERE COMP_CD = #{compCd}
  AND MAIL_TYPE_CD = #{mailTypeCd}

SELECT M.*
FROM TC_MAIL_FORM M
JOIN V_ORGANIZATION_STRUCTURE V ON M.COMP_CD = V.MGR_COMP_CD
WHERE V.DEPT_CD = #{deptCd}
  AND M.MAIL_TYPE_CD = #{mailTypeCd}

mapper.insert:
INSERT INTO TC_MAIL_FORM (
    COMP_CD, MAIL_TYPE_CD, MAIL_TITLE, MAIL_CONT, MAIL_DESC, REG_DT, REG_ID
) VALUES (
    #{compCd}, #{mailTypeCd}, #{mailTitle}, #{mailCont}, #{mailDesc}, NOW(), #{regId}
)

mapper.update:
UPDATE TC_MAIL_FORM
SET MAIL_TITLE = #{mailTitle},
    MAIL_CONT = #{mailCont},
    MAIL_DESC = #{mailDesc},
    MOD_DT = NOW(),
    MOD_ID = #{modId}
WHERE COMP_CD = #{compCd}
  AND MAIL_TYPE_CD = #{mailTypeCd}

mapper.delete:
DELETE FROM TC_MAIL_FORM
WHERE COMP_CD = #{compCd}
  AND MAIL_TYPE_CD = #{mailTypeCd}
